import json
from collections import defaultdict

class WebhookHandler:
    def __init__(self, secret="my_secret"):
        self.secret = secret
        self.handlers = defaultdict(list)  # {event_type: [handler_func, ...]}
        self.processed = []

    def on(self, event_type):
        """Decorator to register a handler for an event type."""
        def decorator(func):
            self.handlers[event_type].append(func)
            return func
        return decorator

    def process(self, event_type, payload):
        """
        Process an incoming webhook event.
        Calls all registered handlers for this event type.
        Returns number of handlers called.
        """
        handlers = self.handlers.get(event_type, [])
        for handler in handlers:
            handler(payload)
        self.processed.append({"type": event_type, "handlers": len(handlers)})
        return len(handlers)

handler = WebhookHandler()

# Register event handlers
@handler.on("push")
def on_push(payload):
    branch = payload.get("ref", "").replace("refs/heads/", "")
    commits = len(payload.get("commits", []))
    print(f"[Push] Branch: {branch}, Commits: {commits}")

@handler.on("push")
def notify_on_push(payload):
    branch = payload.get("ref", "").replace("refs/heads/", "")
    if branch == "main":
        print(f"[Alert] Production push detected!")

@handler.on("pull_request")
def on_pr(payload):
    action = payload.get("action")
    title = payload.get("pull_request", {}).get("title")
    print(f"[PR] Action: {action}, Title: {title}")

@handler.on("issues")
def on_issue(payload):
    action = payload.get("action")
    title = payload.get("issue", {}).get("title")
    print(f"[Issue] {action}: {title}")

# Simulate incoming webhooks
events = [
    ("push", {"ref": "refs/heads/main", "commits": [{}, {}, {}]}),
    ("push", {"ref": "refs/heads/feature/login", "commits": [{}]}),
    ("pull_request", {"action": "opened", "pull_request": {"title": "Add auth module"}}),
    ("issues", {"action": "opened", "issue": {"title": "Login button broken"}}),
    ("unknown_event", {}),
]

for event_type, payload in events:
    count = handler.process(event_type, payload)
    if count == 0:
        print(f"[Warning] No handlers for event: {event_type}")

print(f"\nTotal events processed: {len(handler.processed)}")
